PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE paginas (
  id            TEXT PRIMARY KEY,
  capitulo_id   TEXT NOT NULL REFERENCES capitulos(id) ON DELETE CASCADE,
  numero        INTEGER NOT NULL,
  r2_key        TEXT NOT NULL,   -- 'scancrimson.com/chapters/manga-id/cap-001/001.webp'
  scramble_map  TEXT DEFAULT '[]', -- JSON: '[3,7,1,5,0,8,2,6,4]'
  orden         INTEGER NOT NULL,
  UNIQUE (capitulo_id, numero)
);
CREATE TABLE scans (
  id TEXT PRIMARY KEY,
  nombre TEXT NOT NULL,
  descripcion TEXT,
  logo_r2_key TEXT,
  activo INTEGER DEFAULT 1,
  fecha_creacion TEXT DEFAULT (datetime('now'))
, webhook_discord TEXT, imagen_url TEXT DEFAULT NULL, slug TEXT, discord_template TEXT DEFAULT NULL, redes TEXT DEFAULT NULL, contrato_firmado INTEGER DEFAULT 0, contrato_version INTEGER DEFAULT 0, representante_nombre TEXT, representante_discord TEXT, binance_pay_id TEXT, fecha_firma TEXT);
CREATE TABLE IF NOT EXISTS "usuarios_old" (
  id              TEXT PRIMARY KEY,
  username        TEXT UNIQUE NOT NULL,
  email           TEXT UNIQUE NOT NULL,
  password_hash   TEXT NOT NULL,
  rol             TEXT NOT NULL DEFAULT 'lector'
                  CHECK (rol IN ('lector', 'uploader', 'admin', 'admin_scan')),
  avatar_url      TEXT,
  activo          INTEGER DEFAULT 1,
  fecha_registro  TEXT DEFAULT (datetime('now')),
  ultimo_acceso   TEXT,
  is_superadmin   INTEGER DEFAULT 0,
  scan_id         TEXT
);
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE IF NOT EXISTS "usuarios" (
  id              TEXT PRIMARY KEY,
  username        TEXT UNIQUE NOT NULL,
  email           TEXT UNIQUE NOT NULL,
  password_hash   TEXT NOT NULL,
  rol             TEXT NOT NULL DEFAULT 'lector'
                  CHECK (rol IN ('lector', 'uploader', 'admin', 'admin_scan', 'soporte')),
  avatar_url      TEXT,
  activo          INTEGER DEFAULT 1,
  fecha_registro  TEXT DEFAULT (datetime('now')),
  ultimo_acceso   TEXT,
  is_superadmin   INTEGER DEFAULT 0,
  scan_id         TEXT
, color_acento TEXT DEFAULT NULL, bio TEXT DEFAULT NULL, display_name TEXT DEFAULT NULL, fecha_nacimiento TEXT);
CREATE TABLE IF NOT EXISTS "mangas" (
  id                   TEXT PRIMARY KEY,
  titulo               TEXT NOT NULL,
  titulo_alt           TEXT,
  descripcion          TEXT,
  generos              TEXT DEFAULT '[]',
  tipo                 TEXT NOT NULL DEFAULT 'manga'
                       CHECK (tipo IN ('manga', 'manhwa', 'manhua')),
  estado               TEXT NOT NULL DEFAULT 'en_curso'
                       CHECK (estado IN ('en_curso', 'completado', 'pausado')),
  cover_r2_key         TEXT,
  uploader_id          TEXT,
  views_total          INTEGER DEFAULT 0,
  fecha_creacion       TEXT DEFAULT (datetime('now')),
  fecha_actualizacion  TEXT DEFAULT (datetime('now')),
  scan_id              TEXT,
  es_adulto            INTEGER NOT NULL DEFAULT 0
, views_mes INTEGER DEFAULT 0, slug TEXT, joint_scan_id TEXT, joint_status TEXT DEFAULT 'pendiente', es_novela INTEGER DEFAULT 0);
CREATE TABLE comentarios (
  id          TEXT PRIMARY KEY,
  manga_id    TEXT NOT NULL REFERENCES mangas(id) ON DELETE CASCADE,
  usuario_id  TEXT NOT NULL,
  username    TEXT NOT NULL,
  contenido   TEXT NOT NULL,
  fecha       TEXT DEFAULT (datetime('now')),
  es_visible  INTEGER DEFAULT 1
);
CREATE TABLE IF NOT EXISTS "capitulos" (
  id               TEXT PRIMARY KEY,
  manga_id         TEXT NOT NULL REFERENCES mangas(id) ON DELETE CASCADE,
  numero           REAL NOT NULL,
  titulo           TEXT,
  uploader_id      TEXT,
  estado           TEXT NOT NULL DEFAULT 'borrador'
                   CHECK (estado IN ('borrador', 'publicado', 'rechazado', 'programado')),
  notas_admin      TEXT,
  views            INTEGER DEFAULT 0,
  fecha_subida     TEXT DEFAULT (datetime('now')),
  fecha_publicacion TEXT, joint_scan_id TEXT,
  UNIQUE (manga_id, numero)
);
CREATE TABLE system_logs (
    id TEXT PRIMARY KEY,
    tipo TEXT NOT NULL,
    ip TEXT,
    user_agent TEXT,
    detalles TEXT,
    fecha DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE views_dedup (capitulo_id TEXT, viewer_key TEXT, fecha TEXT, PRIMARY KEY (capitulo_id, viewer_key, fecha));
CREATE TABLE manga_views_dedup (manga_id TEXT, viewer_key TEXT, fecha TEXT, PRIMARY KEY (manga_id, viewer_key, fecha));
CREATE TABLE marcadores (
    usuario_id TEXT NOT NULL,
    manga_id TEXT NOT NULL,
    creado_en TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (usuario_id, manga_id),
    FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE CASCADE,
    FOREIGN KEY (manga_id) REFERENCES mangas(id) ON DELETE CASCADE
);
CREATE TABLE historial_lectura (
    usuario_id TEXT NOT NULL,
    manga_id TEXT NOT NULL,
    capitulo_id TEXT NOT NULL,
    leido_en TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (usuario_id, manga_id),
    FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE CASCADE,
    FOREIGN KEY (manga_id) REFERENCES mangas(id) ON DELETE CASCADE,
    FOREIGN KEY (capitulo_id) REFERENCES capitulos(id) ON DELETE CASCADE
);
CREATE TABLE tickets (
  id TEXT PRIMARY KEY,
  usuario_id TEXT REFERENCES usuarios(id) ON DELETE SET NULL,
  tipo TEXT NOT NULL CHECK (tipo IN ('sugerencia', 'soporte', 'reporte')),
  mensaje TEXT NOT NULL,
  contacto TEXT,
  estado TEXT NOT NULL DEFAULT 'pendiente' CHECK (estado IN ('pendiente', 'en_proceso', 'resuelto')),
  fecha_creacion TEXT DEFAULT (datetime('now'))
);
CREATE TABLE test_c (id INT, p_id INT REFERENCES test_p(id) ON DELETE CASCADE);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_pags_capitulo  ON paginas(capitulo_id, orden);
CREATE INDEX idx_comentarios_manga ON comentarios(manga_id, es_visible);
CREATE UNIQUE INDEX idx_mangas_slug ON mangas(slug) WHERE slug IS NOT NULL;
CREATE UNIQUE INDEX idx_scans_slug ON scans(slug) WHERE slug IS NOT NULL;
CREATE INDEX idx_marcadores_usuario ON marcadores(usuario_id);
CREATE INDEX idx_historial_usuario ON historial_lectura(usuario_id);
