INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('b6678406-7b44-446b-835d-c0b40e7d6f70','Caida',NULL,'Cuando la criminal de toda la vida, Seung-Ji, se ve traicionada por su antiguo jefe, se une a un negocio de contrabando emergente para mantenerse oculta. Su objetivo es encontrar la oportunidad de aprovecharse del negocio para obtener dinero y huir de la ciudad, pero un obstáculo llamado Yeong-Won se interpone en sus planes. Inexperta e ingenua, Yeong-Won trabaja en lugar de su tía como superior de Seung-Ji. Enamorarse es un lujo para las personas en su línea de trabajo, pero el deseo de beneficio económico de Seung-Ji podría estar transformándose en el deseo por algo que no puede permitirse...','["Romance","Drama","Yuri","GL (Girls Love)","Josei"]','manhwa','en_curso','scancrimson.com/covers/b6678406-7b44-446b-835d-c0b40e7d6f70.png','admin-001',92,'2026-06-04 20:59:15','2026-06-23 03:16:39','scan-001',0,13,'caida','scan-025989b6','aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('c633f306-8a91-42c0-bd37-5b8aee42823c','El protagonista masculino es el gran duque de cabello negro del norte',NULL,'La protagonista renace como la amiga de la infancia de un niño noble del Norte, un chico frágil que en el futuro sufrirá por amor. Decidida a cambiar su destino, intenta ayudarlo a convertirse en un duque fuerte, elegante y respetado. Pero mientras lo cuida y guía, el muchacho comienza a sentir un afecto profundo y posesivo por ella. Lo que empezó como un plan para mejorar su vida termina convirtiéndose en una relación inesperadamente dulce… y complicada. «En ese caso, ¡lo ayudaré a convertirse en el perfecto Duque Moreno del Norte y a encontrar el amor!». Ese era mi plan, pero... ¿Por qué nuestro Setsu es tan lindo y dulce? ¿De verdad podré tener éxito? «Solo soy amable contigo».','["Drama","Fantasía","Romance"]','manhwa','en_curso','scancrimson.com/covers/c633f306-8a91-42c0-bd37-5b8aee42823c.jpg','0f697028-4a70-4d8c-9ef7-3f578fbf2886',7,'2026-06-06 01:48:39','2026-06-06 01:48:39','scan-891bd645',0,1,'el-protagonista-masculino-es-el-gran-duque-de-cabello-negro-del-norte',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('8704c569-1a0c-4d18-b2b1-e87d4e3469d2','Koori no Jouheki',NULL,'Inepta para relacionarse con la gente, Hikawa Koyuki mantiene una barrera entre ella y los demás. Pasa su tiempo en el instituto aislada, completamente sola. Al menos hasta que conoce a Amamiya Minato, ¡quien por alguna razón no deja de acortar la distancia entre ellos! La distante Koyuki, la popular Miki, el desinhibido Minato y el simpático y amable Youta, miembro del equipo de baloncesto. ¡Esta es la historia de estos cuatro personajes un tanto complicados y su fascinante y torpe juventud!','["Comedia","Drama","Vida Escolar","Romance"]','manga','en_curso','scancrimson.com/covers/8704c569-1a0c-4d18-b2b1-e87d4e3469d2.webp','0f697028-4a70-4d8c-9ef7-3f578fbf2886',39,'2026-06-06 02:31:15','2026-06-19 05:27:25','scan-891bd645',0,16,'koori-no-jouheki',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('d68d9e70-37b6-4bd7-bc39-f94cf7d54d97','Casate conmigo otra vez',NULL,'En medio de un mar de flores amarillas en el jardín está mi esposo, Kardi. “Me dijiste que te gustaban estas flores antes”. Un hombre dulce que recuerda las palabras dichas en el pasado y hace un campo lleno de narcisos. Incluso si pudiera ser bastante egoísta, soy feliz cada día sabiendo que no te perderé. Incluso si muero en tu lugar. “Nunca me he arrepentido de ser tu pareja”. “De los treinta años que he vivido, estos 10 años contigo han sido los más felices”. La gente lo llamaría una tragedia, pero el momento más pacífico de mi vida fue el tiempo que pasé contigo. “Te amo, Kardi”. Incluso si vuelvo atrás en el tiempo, lo que tengo que hacer está decidido. Voy a encontrarme con Kardi de nuevo.','["Drama","Fantasía","Romance"]','manhwa','en_curso','scancrimson.com/covers/d68d9e70-37b6-4bd7-bc39-f94cf7d54d97.webp','6b1571c9-1348-41d4-9cab-59483f9d1306',13,'2026-06-06 04:26:32','2026-06-06 04:26:32','scan-001',0,2,'casate-conmigo-otra-vez',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('850c33a7-d0fe-4638-8641-0d0317c427ce','Conquistador de corazones palpitantes',NULL,'Abrí los ojos, pero ¿dónde estoy? Daeun comprendió instintivamente que cayó en el mundo del simulador de amor de chicos (chicas) guapos como Diana. Al mirar a su alrededor, ¡ve corazones sobre la cabeza de los demás! ¡Hombres, mujeres e incluso animales que pasan son todos objetivos! Diana, pensando que todo esto es un sueño, crea un plan para comenzar un harén inverso...','["Romance","Fantasía","Comedia"]','manhwa','en_curso','scancrimson.com/covers/850c33a7-d0fe-4638-8641-0d0317c427ce.webp','6b1571c9-1348-41d4-9cab-59483f9d1306',6,'2026-06-06 04:37:39','2026-06-06 04:37:39','scan-001',0,0,'conquistador-de-corazones-palpitantes',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('24f18687-2c76-4daa-a7cb-a97bbd0891f8','Pero tú eres en 2D.',NULL,'Choi Soo-ah, una estudiante de secundaria marginada, es arrastrada un día por una fuerza misteriosa al interior de su romance de historietas favorito. La persona que conoce en ese lugar, tan extraño como familiar, es... ¡¿su personaje favorito y protagonista masculino, Jung Ji-hoon?! Un drama cotidiano sobre el crecimiento de Soo-ah, una fan inmadura, mientras comparte las alegrías y penas con sus amigos dentro del cómic.','["Drama","Fantasía","Romance"]','manhwa','en_curso','scancrimson.com/covers/24f18687-2c76-4daa-a7cb-a97bbd0891f8.png','6b1571c9-1348-41d4-9cab-59483f9d1306',59,'2026-06-06 04:50:15','2026-06-06 04:50:15','scan-001',0,7,'pero-tu-eres-en-2d',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('a25d406e-5ce0-4a7e-ace6-c38fcdbd5821','Atados por el pecado',NULL,replace('“Alfa Policía Leopardo de las Nieves de temperamento fuerte × Alfa Señor del Crimen Tigre intrigante”\n\nTras renacer, un policía de élite cae en cautiverio y es acogido por su némesis de toda la vida. La sospecha y el enredo los mantienen unidos, hasta que los dos finalmente se convierten en compañeros del destino','\n',char(10)),'["BL","Drama","Romance"]','manhwa','en_curso','scancrimson.com/covers/a25d406e-5ce0-4a7e-ace6-c38fcdbd5821.png','6b1571c9-1348-41d4-9cab-59483f9d1306',19,'2026-06-06 04:58:01','2026-06-06 04:58:01','scan-001',0,1,'atados-por-el-pecado',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('2ce14647-7bc7-43c5-a7df-5458d9d23def','Estimado Sr. Candy',NULL,replace('La competencia trienal Candy Star se acerca de nuevo. Para cumplir el último deseo de su madre de obtener el honor de la Candy Star, Mengtai, el dueño de MR. CANDY, le pidió a su compañero de la infancia, Ning Te, que desarrollaran juntos un nuevo dulce. Sin embargo, el proceso de creación del nuevo dulce no fue tan fluido como se esperaba. Mengtai se frustró por un tiempo y salió corriendo de la tienda. Justo cuando Mengtai estaba angustiado, un hada apareció frente a él, afirmando que podía usar magia para ayudarlo a fabricar dulces deliciosos.\nPara demostrar que es capaz de hacer dulces deliciosos sin depender de Ning Te, ¿aceptará el enfurecido Mengtai la tentación del hada?','\n',char(10)),'["BL","Fantasía","Romance"]','manhua','en_curso','scancrimson.com/covers/2ce14647-7bc7-43c5-a7df-5458d9d23def.webp','6b1571c9-1348-41d4-9cab-59483f9d1306',6,'2026-06-06 05:10:31','2026-06-06 05:11:03','scan-001',0,0,'estimado-sr-candy',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('ef911fe9-dabc-46c3-abd6-67f6dfac089f','El hermano impuro de mi amiga',NULL,'¿No es mejor un pollito joven que un viejo vándalo? Puedo hacerlo varias veces al día. Yo no tenía derecho a dar un sermón como una chica confuciana, preguntando qué clase de discurso audaz podía estar diciendo un jovencito. Hazte responsable por dormir conmigo. Desde entonces, sigo pensando en ti y mi erección no se quita. Al chico que apreciaba como a mi propio hermano, todavía está duro así. A Nam Doha, que era más lindo y adorable que un muñeco cuando era pequeño, acuéstate conmigo, Noona. Le quité la virginidad en el momento en que cumplió veinte años. Me estoy volviendo loca, Doyoon… ¿Qué debería hacer? Solía contarle a Doyoon cada pequeño detalle de mis preocupaciones, especialmente sobre mi vida amorosa, y pedirle consejo. No había secretos entre nosotros. Pero ahora, por primera vez, Nam Doyoon tenía un secreto.','["Romance","Drama"]','manhwa','en_curso','scancrimson.com/covers/ef911fe9-dabc-46c3-abd6-67f6dfac089f.jpg','6b1571c9-1348-41d4-9cab-59483f9d1306',11,'2026-06-06 05:21:48','2026-06-06 05:38:29','scan-001',1,0,'el-hermano-impuro-de-mi-amiga',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('f66e4035-45f9-4ed9-abab-ecd5b4c3c2b8','Me enamoré del abuelo de mi ex',NULL,NULL,'["Aventura","Comedia","Drama","Fantasía","Romance"]','manga','en_curso','scancrimson.com/covers/f66e4035-45f9-4ed9-abab-ecd5b4c3c2b8.webp','8e552c99-be35-4cb5-82a8-3ecfb044f307',9,'2026-06-06 20:45:00','2026-06-08 03:04:14','scan-f9d111f2',0,0,'me-enamore-del-abuelo-de-mi-ex',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('093ef322-b0b0-4ed1-9376-d13a64861915','Domando a un Munchkin',NULL,replace('¡¿Por qué tenía que reencarnar justo en ESTE personaje?!\n\nReencarné en una novela de fantasía como el villano Kinémia Rion, quien carga con el rencor ancestral de su familia.\nSi todo sigue el curso original, mi destino es acabar en la guillotina a manos de los habitantes del feudo.\n\nPara evitarlo, decido reunir a los munchkins antes que el protagonista original y reconstruir el territorio…\npero surge un problema.\n\n—¿Hola?\n—¡¿Por qué estás aquí?!\n\nAyan Krotz, el mago munchkin que en la obra original ayudó a enviarme a la guillotina.\nEn esta vida intenté no involucrarme con él y lo eché rápidamente del feudo, pero…\n\n—Me atraparon.\n\n¡¿Por qué demonios sigue regresando atrapado?!\n\nUna obsesión munchkin totalmente no deseada.\n¿Por qué Ayan sigue siendo capturado y traído de vuelta al feudo?\n¿Y podrá Kinémia revivir con éxito a la Gran Casa Ducal de Rion?','\n',char(10)),'["Romance","Realeza","Fantasía","Magia","Isekai","Shoujo"]','manhwa','en_curso','scancrimson.com/covers/093ef322-b0b0-4ed1-9376-d13a64861915.png','b834ee67-f2aa-4f7d-bcd4-76e8404e02c4',2,'2026-06-07 01:44:50','2026-06-07 01:46:17','scan-4b2f06f1',0,1,'domando-a-un-munchkin',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('972a2d91-1b18-484a-aa75-984a7c77213c','Nada Falso Sobrevive ante la Señorita',NULL,replace('Elisha Rionette, la joven dueña de una antigua casa de empeños. En su primera vida, fue engañada por un pariente lejano que aseguró que cuidaría de su abuelo enfermo. Despojada de todos los bienes de su abuelo, terminó encontrando un final miserable. Pero, como si fuera un milagro… se le concedió una segunda vida.\n\n—“Mi abuelo. La casa de empeños. Mi vida. No dejaré que nadie me los arrebate otra vez.”\n\nTras regresar de la muerte, Elisha decide proteger tanto a su abuelo como la casa de empeños que él le confió. Sin embargo, sus días están lejos de ser tranquilos.\n\n—“¿Esta casa de empeños también comercia con personas?”\n—Clientes que preguntan sin pudor si pueden ser vendidos.\n\n—“¿Quién te dio permiso para montar un negocio aquí?”\n—Matones que lanzan amenazas sin dudar.\n\n—“¿C-cómo supiste que esto era una reliquia sagrada?!”\n—Ladrones evidentes intentando vender objetos robados.\n\nRodeada por un flujo constante de clientes extraños y problemáticos (¿?) y sus incesantes interferencias,\n¿podrá Elisha mantener a salvo a su abuelo y la casa de empeños?','\n',char(10)),'["Romance","Fantasía","Shoujo","Regresión","Regresor","Viaje en el Tiempo","Venganza","Realeza","Reencarnación"]','manhwa','en_curso','scancrimson.com/covers/972a2d91-1b18-484a-aa75-984a7c77213c.jpeg','b834ee67-f2aa-4f7d-bcd4-76e8404e02c4',4,'2026-06-07 01:50:27','2026-06-07 01:50:27','scan-4b2f06f1',0,0,'nada-falso-sobrevive-ante-la-senorita',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('228a2e71-278a-47de-bc61-36a2ab4fab2a','¿Está bien que un asesino sea un ídol?',NULL,replace('[Presencia el asesinato cometido por un compañero de su mismo grupo de ídolos.]\nLee Yumin debuta por segunda vez en un grupo, decidido a que esta vez no fracasará y tendrá éxito a toda costa. Mientras practica para una importante presentación en una entrega de premios de fin de año, termina siendo testigo de cómo el líder del grupo, Han Segye, comete un asesinato. Segye lo amenaza para que guarde el secreto por el bien del grupo, pero al mismo tiempo se vuelve más afectuoso físicamente que antes, dejando a Yumin nervioso y profundamente confundido.\n¿Estoy loco...? ¡¿Por qué mi corazón late por un asesino?!\nUn asesino a sangre fría, pero también un líder amable y una figura de hermano mayor, ¿cuál es el verdadero Segye?','\n',char(10)),'["BL (Boys Love)","Romance","Drama","Idol","Crimen"]','manhwa','completado','scancrimson.com/covers/228a2e71-278a-47de-bc61-36a2ab4fab2a.png','6b1571c9-1348-41d4-9cab-59483f9d1306',11,'2026-06-07 04:02:04','2026-06-07 04:02:04','scan-001',0,0,'esta-bien-que-un-asesino-sea-un-idol',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('b7c6e4da-5be9-461b-8d4f-6414d2a42750','El cautiverio de benjamín ',NULL,'Benjamin Barker, agente especial del CBI, intenta arrestar a Ian Basti, el jefe de una importante organización criminal, pero es superado y capturado. Como prisionero de Ian, Benjamin es sometido a innumerables torturas sexuales e incluso abandonado por sus compañeros. A pesar de ello, decide permanecer junto a Ian para aprender más sobre el funcionamiento interno de la organización y sus operaciones de narcotráfico. ¿Sobrevivirá Benjamin a esta terrible experiencia o el control del jefe mafioso frustrará sus planes de escape?','["BL (Boys Love)","Sadomasoquismo","Mafia","Crimen","Detectives","Maduro","Adulto","Psicológico"]','manhwa','en_curso','scancrimson.com/covers/b7c6e4da-5be9-461b-8d4f-6414d2a42750.webp','686aeaa4-0719-4f9d-aae7-a145ae087c74',64,'2026-06-07 16:07:17','2026-06-07 16:40:04','scan-025989b6',1,5,'el-cautiverio-de-benjamin',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('c6de57a9-b1b1-452a-a8c8-30564fd76b12','Psyche - SIN CENSURA',NULL,replace('Psyche, un miembro de la realeza que ha permanecido años encarcelado en una torre, emerge para descubrir que su reino ha sido destruido por una rebelión y que el gobierno de su familia ha sido condenado como cruel y corrupto. Mientras llora la pérdida de su hermano Michele, Psyche es capturado por el Ejército de Liberación, liderado por Anteros, quien le propone matrimonio con el objetivo de aprovechar una profecía y “destruir el reino” por completo.\n\nForzado a aceptar este peligroso matrimonio, Psyche oculta su odio mientras planea su venganza… pero pronto comienza a descubrir que, quizá, su resentimiento está dirigido hacia la persona equivocada.','\n',char(10)),'["Histórico","Adulto","Romance","BL (Boys Love)","Venganza","Josei","Tragedia","Drama"]','manhwa','en_curso','scancrimson.com/covers/c6de57a9-b1b1-452a-a8c8-30564fd76b12.webp','b834ee67-f2aa-4f7d-bcd4-76e8404e02c4',5,'2026-06-07 16:34:13','2026-06-07 16:34:13','scan-4b2f06f1',1,0,'psyche-sin-censura',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('125459f8-3931-4474-bc32-abc440f0e61b','Las Estrellas de Rock Nunca Mueren',NULL,'Jungseo se reencuentra con Hyosin, el chico al que admiraba en el instituto, pero un accidente relacionado con el alcohol deja a Hyosin con la nariz rota y viviendo bajo el techo de Jungseo. Al empezar a convivir, Jungseo se da cuenta de que Hyosin no se parece en nada a la persona que antes idolatraba… y decide ayudarlo a recuperar el valor para perseguir su sueño nuevamente.','["Romance","Josei","Música","BL (Boys Love)"]','manhwa','en_curso','scancrimson.com/covers/125459f8-3931-4474-bc32-abc440f0e61b.webp','b834ee67-f2aa-4f7d-bcd4-76e8404e02c4',6,'2026-06-07 16:36:19','2026-06-07 16:36:19','scan-4b2f06f1',0,1,'las-estrellas-de-rock-nunca-mueren',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('82de4d04-d110-4da3-afb4-705159a43d8e','Mi destino trágico Isekai',NULL,replace('Nuestra protagonista se reencarna en la noble considerada “villana” de su juego otome favorito… pero su personaje preferido es solo un secundario.\nDecidida a cambiar su destino, intenta romper el compromiso con el príncipe al que debía casarse en la historia original. Sin embargo, las cosas no salen como esperaba: el destino da un giro inesperado, poniendo a prueba su determinación, su afecto y su libertad.\n\nUna historia donde el amor, la obsesión y el destino se entrelazan en un camino lleno de desafíos y decisiones difíciles.','\n',char(10)),'["Maduro","Adulto","Josei"]','manga','en_curso','scancrimson.com/covers/82de4d04-d110-4da3-afb4-705159a43d8e.webp','051e26e6-ed75-4d91-9da6-cc255852921f',123,'2026-06-07 23:48:17','2026-06-07 23:49:13','scan-29052422',1,6,'mi-destino-tragico-isekai',NULL,'pendiente',0);
