INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('71a73d1e-00a7-47bb-8412-35aa8ce60a9f','Las hermanas imperfectas',NULL,'«Hermana mayor, somos las únicas hermanas que tenemos, ¿verdad?» Ryu Sohee es una estudiante de secundaria que de niña padeció una enfermedad grave, pero se ha recuperado y ahora vive una vida ordinaria. Tiene una hermana menor, Ryu Ayoung, quien sigue siendo frágil y enfermiza. Ayoung adora y depende profundamente de su hermana mayor, pero para Sohee, esa devoción empieza a sentirse asfixiante. Tras cierto incidente, el vínculo entre ellas comienza a resquebrajarse y las dos hermanas se sienten cada vez más incómodas la una con la otra. Un thriller de misterio cruel sobre dos hermanas, que se desarrolla en medio de los secretos ocultos de su familia.','["Horror","Drama","Magia Oscura","Misterio"]','manhwa','en_curso','scancrimson.com/covers/71a73d1e-00a7-47bb-8412-35aa8ce60a9f.webp','6b1571c9-1348-41d4-9cab-59483f9d1306',9,'2026-06-13 18:00:34','2026-06-16 03:45:41','scan-001',0,1,'las-hermanas-imperfectas',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('a5cdde34-d9b2-4b3b-b4dd-bbc0b56e4296','El Cautiverio de Benjamín (CS)',NULL,'El agente Benjamin es capturado mientras sigue la pista del principal sospechoso, el jefe mafioso Yian. Despertado en una ineludible habitación llena de aparatos de tortura, Benjamin, que se niega a ceder incluso tras interminables torturas, permanece al lado de Yian e intenta descubrir los secretos de la organización de narcotraficantes','["Tragedia","Adulto","Psicológico","Thriller","Yaoi","Sadomasoquismo","BL (Boys Love)","Mafia","Detectives","Crimen"]','manhwa','en_curso','scancrimson.com/covers/a5cdde34-d9b2-4b3b-b4dd-bbc0b56e4296.webp','686aeaa4-0719-4f9d-aae7-a145ae087c74',4,'2026-06-15 21:26:31','2026-06-15 21:26:31','scan-025989b6',1,0,'el-cautiverio-de-benjamin-cs',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('4fc672c1-2bba-4a32-8587-c525c4ced4fd','Esta vez ajustaré cuentas',NULL,'Irene, la esposa de un noble menor en el Reino de Westaria, recibe noticias devastadoras—ambos de sus padres han fallecido. Cuando busca a su esposo, Cosmo, descubre que su matrimonio era una farsa, destinado solo a derribar a su familia. Incapaz de soportar la traición, Irene se desvive solo para despertar seis meses antes del día de su boda. Esta vez, armada con sus excepcionales habilidades médicas, promete acercándose al regente de los reinos, Base. Mientras tanto, Cosmo todavía comprometido con Irene— comienza a tambalearse ante su repentina frialdad. Entre estos dos hombres, ¿tendrá éxito Irene en llevar a cabo su venganza?','["Acción","Aventura","Drama","Fantasía","Romance"]','manhwa','en_curso','scancrimson.com/covers/4fc672c1-2bba-4a32-8587-c525c4ced4fd.webp','8e552c99-be35-4cb5-82a8-3ecfb044f307',3,'2026-06-16 02:40:41','2026-06-16 02:48:27','scan-f9d111f2',0,0,'esta-vez-ajustare-cuentas',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('fe1708cc-a34a-40db-aa6f-bd3a567ba879','El siervo por contrato.',NULL,'Sioanna siempre ha estado desesperada por obtener la atención de su padre. Desafortunadamente, la muerte de su madre ha tensado su relación desde hace mucho tiempo. Y sin otra familia aparte de un hermano mayor abusivo, rápidamente desarrolla afecto por un nuevo esclavo traído por su padre. ¿Podrán estos dos, con sus dolorosas crianzas, encontrar en sí mismos la fuerza para darle una oportunidad más a una verdadera conexión?','["Romance","Drama","Fantasía","Shoujo","Josei"]','manhwa','en_curso','scancrimson.com/covers/fe1708cc-a34a-40db-aa6f-bd3a567ba879.webp','6b1571c9-1348-41d4-9cab-59483f9d1306',6,'2026-06-17 06:05:51','2026-06-17 06:06:32','scan-001',0,0,'el-siervo-por-contrato',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('8b0c026b-c450-4084-bd5a-cfaece3e36c9','Zona de seguridad antisocial',NULL,'Si no fueras mujer... no te necesitaría. Han pasado tres meses desde el brote zombi global. A medida que surgen poderosos zombis mutantes y la infraestructura social colapsa rápidamente, las personas en este mundo roto y sin ley han recurrido a extremos para sobrevivir. Mientras tanto, Bo-yeon, quien se había estado escondiendo en un búnker seguro, es descubierta y amenazada por Do-gyeong. Para sobrevivir, comienza a vivir bajo su protección como la ''mujer'' de este hombre frío y reservado... Un grillete ineludible,','["Josei","Drama","Fantasía","Horror","Romance","Psicológico","Acción","Apocalipsis"]','manhwa','en_curso','scancrimson.com/covers/8b0c026b-c450-4084-bd5a-cfaece3e36c9.webp','6b1571c9-1348-41d4-9cab-59483f9d1306',18,'2026-06-18 01:30:12','2026-06-18 01:51:22','scan-001',1,4,'zona-de-seguridad-antisocial',NULL,'pendiente',0);
