INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('f0046e7f-2528-4728-aeb9-3082f2279d38','Mi estrella de la suerte',NULL,'Cuando Star Mu tenía cinco años, un chico bonito llamado Austin Si apareció de repente en su vida como un paisaje primaveral, convirtiéndose en su amigo de la infancia. En su primer encuentro, mientras jugaban con barro, Star fue despreciada por Austin y pensó que le caía mal. Sin embargo, no sabía que ese muchacho distante y llamativo ya se había sentido atraído por su alegría y su sonrisa. Con el paso de los años, esos sentimientos fueron creciendo y volviéndose cada vez más profundos…','["Comedia","Romance","Vida Escolar"]','manhua','en_curso','scancrimson.com/covers/f0046e7f-2528-4728-aeb9-3082f2279d38.webp','0f697028-4a70-4d8c-9ef7-3f578fbf2886',1,'2026-06-21 00:13:49','2026-06-21 00:13:49','scan-891bd645',0,0,'mi-estrella-de-la-suerte',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('3fae124c-c80b-488e-ba51-277b1187d12d','Por favor, enséñame, Sunbae-nim',NULL,'El mayor sueño de Sua se cumple cuando tiene la oportunidad de coprotagonizar una película con su ídolo de toda la vida, Seohyeon. Pero la línea entre lo profesional y lo personal comienza a desdibujarse cuando las dos mujeres tienen que grabar una escena subida de tono. Incapaz de concentrarse, Sua le pide a Seohyeon que la ayude a ensayar la escena. Todo debería estar bien, ya que solo es actuación... ¿verdad?','["Yuri","Recuentos de la Vida (Slice of Life)","Maduro","Adulto","Ecchi","GL (Girls Love)"]','manhwa','completado','scancrimson.com/covers/3fae124c-c80b-488e-ba51-277b1187d12d.webp','686aeaa4-0719-4f9d-aae7-a145ae087c74',2,'2026-06-21 18:48:57','2026-06-21 18:48:57','scan-025989b6',1,0,'por-favor-ensename-sunbae-nim',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('5e3dbe8e-cea0-4ee7-9cd3-cccc4f124651','El nerd no es para nada bueno',NULL,'Desesperada por salvar sus calificaciones, Vivi, estudiante de segundo año, comienza a estudiar con la tranquila estudiante de primer nivel con la que nadie habla. Pero cuanto más estudia con él, más se da cuenta de que no se parece en nada al nerd tímido que parece ser. Él guarda un oscuro secreto... y tiene todo que ver con ella','["Drama","Romance"]','manhua','en_curso','scancrimson.com/covers/5e3dbe8e-cea0-4ee7-9cd3-cccc4f124651.webp','8e552c99-be35-4cb5-82a8-3ecfb044f307',1,'2026-06-21 18:58:35','2026-06-21 18:58:35','scan-f9d111f2',0,0,'el-nerd-no-es-para-nada-bueno',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('41ed91f7-2bc0-4393-97ba-1cfaf382c197','Puedes Odiarme ',NULL,'¿Es posible recuperar lo que dejaste atrás? ¿O estás destinada a seguir adelante sola? Josefa regresa a su ciudad natal después de muchos años y, nada más llegar, la recibe el fantasma de un amor que creía haber olvidado.','["Romance","Psicológico","Yuri","GL (Girls Love)"]','manhwa','completado','scancrimson.com/covers/41ed91f7-2bc0-4393-97ba-1cfaf382c197.webp','686aeaa4-0719-4f9d-aae7-a145ae087c74',2,'2026-06-21 19:22:25','2026-06-22 03:36:09','scan-025989b6',0,0,'puedes-odiarme',NULL,'pendiente',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('abd40f64-9c4e-4f18-95d6-d67ac34e3dbe','Cuerpo Hermoso ',NULL,'Han Woojin, un ermitaño obsesionado con el laboratorio, guarda un secreto escandaloso: su pasión por la ciencia es literal. Cuando logra un descubrimiento, su cuerpo reacciona con una intensidad física incontrolable que le ha valido el apodo de Woojin el Loco. Guiado por una lógica fría, se dirige a la montaña Deokmu para desmentir los rumores de un duende que otorga oro. En cambio, encuentra a Baekbaek, un dios de la riqueza de belleza deslumbrante. Olvídense del oro, Woojin ha encontrado el espécimen definitivo... y está dispuesto a experimentar hasta que ambos alcancen su límite.','["Sobrenatural","Superpoderes","Magia","Psicológico","Fantasía","Drama","Maduro","Adulto","BL (Boys Love)","Yaoi","Sadomasoquismo"]','manhwa','completado','scancrimson.com/covers/abd40f64-9c4e-4f18-95d6-d67ac34e3dbe.webp','686aeaa4-0719-4f9d-aae7-a145ae087c74',8,'2026-06-23 01:20:15','2026-06-23 01:20:15','scan-025989b6',1,0,'cuerpo-hermoso',NULL,'aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('25874453-4cd6-4afe-a828-cdc08ac7711d','Llamada privada ',NULL,'En un mundo donde los alfas y los omegas son solo leyendas urbanas, Doha es un omega dominante poco común que suele lidiar con su ciclo de celo mediante encuentros casuales de una noche. Un día, usa un servicio de emparejamiento y lo emparejan con un alfa llamado Jihwan. Las cosas se vuelven inesperadamente intensas. Abrumado por las feromonas, Doha olvida las precauciones y termina atrapado, quedando en estado de shock. Sin embargo, Jihwan parece completamente imperturbable ante la situación y, con audacia, sugiere que se vean de nuevo, diciendo: "No me digas que tienes miedo porque soy un alfa...".','["BL (Boys Love)","Yaoi","Omegaverse","Recuentos de la Vida (Slice of Life)","Maduro","Adulto"]','manhwa','completado','scancrimson.com/covers/25874453-4cd6-4afe-a828-cdc08ac7711d.webp','686aeaa4-0719-4f9d-aae7-a145ae087c74',13,'2026-06-23 02:02:54','2026-06-23 02:02:54','scan-025989b6',1,2,'llamada-privada',NULL,'aprobado',0);
