INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('f57ea7e6-628f-44b8-b9d0-81ba5cc60ac2','Me Odias',NULL,'Ji-un y Yu-seon forman pareja al comienzo del semestre. Ji-un se esfuerza por acercarse a Yu-seon, pero este se muestra frío con él. ¿Cuál será la razón por la que Yu-seon siente aversión por Ji-un?','["Vida Escolar","Escolar","Recuentos de la Vida (Slice of Life)","Adulto","Maduro","GL (Girls Love)","Yuri"]','manhwa','completado','scancrimson.com/covers/f57ea7e6-628f-44b8-b9d0-81ba5cc60ac2.webp','686aeaa4-0719-4f9d-aae7-a145ae087c74',2,'2026-06-24 14:10:15','2026-06-24 14:10:15','scan-025989b6',1,0,'me-odias',NULL,'aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('388afa99-4417-4f4f-be7a-7b366d1277ae',' Sándwich de Tocino, Lechuga y Tomate',NULL,'La historia poliamorosa entre dos hermanos gemelos Pancitos, una fresca Lechuga, un crujiente tocino y por último un jugoso Tomate que hará gruñir a tu estómago.  Por eso, afírmate tu cinturón porque el resultado final hará que se te caigan los pantalones…!!! ','["Romance","Comedia","Drama","Fantasía","Oficina","Cocina","BL (Boys Love)","Yaoi"]','manga','completado','scancrimson.com/covers/388afa99-4417-4f4f-be7a-7b366d1277ae.webp','33715907-b8ae-4d68-85c7-3534a8511c2c',2,'2026-06-24 16:00:11','2026-06-24 16:00:11','scan-7d5cc0bc',0,0,'sandwich-de-tocino-lechuga-y-tomate',NULL,'aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('27c153ba-7a59-48ec-9a2b-4b8483bef739','Anata ga Papa no Unmei Desuka',NULL,'Fukano, un Alfa, ha seguido el camino de la élite que deseaban los que le rodean. Lejos de tener una pareja, nunca ha tenido un compañero, ni siquiera un Omega, pero conoce a Minemori, un Omega, en el trabajo por primera vez. Tiene un hijo y se supone que tiene a su destinado, pero por alguna razón no puede evitar sentir curiosidad por él... ¡y un día, Minemori sufre un ataque de calor en su casa! "No me importa si tiene pareja. Tengo que proteger a estos dos" - por primera vez en su vida, Fukano se deja llevar por un impulso al ver a padre e hijo abrazados, ¡y pide una relación en el acto!','["Romance","Comedia","Omegaverse","Drama","BL (Boys Love)","Yaoi"]','manga','completado','scancrimson.com/covers/27c153ba-7a59-48ec-9a2b-4b8483bef739.webp','33715907-b8ae-4d68-85c7-3534a8511c2c',3,'2026-06-24 16:18:25','2026-06-24 16:18:25','scan-7d5cc0bc',0,3,'anata-ga-papa-no-unmei-desuka',NULL,'aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('7ac14f57-95da-49b8-a274-9882743f140d','Amaregulus: El  General de Compañía',NULL,'"Por favor, devora este cuerpo que ha sido madurado para ti". La historia del despiadado amor nocturno entre un hermoso príncipe y un rudo guerrero comienza ahora.  Érase una vez en cierto país donde  existía la costumbre de que los guerreros retirados se convirtieran en "Guerreros dragón" para calmar los deseos sexuales de los guerreros activos. Anton, que se ha convertido en un guerrero dragón tras ser herido en el campo de batalla, recibe la noticia de que su compañero nocturno es Julius, un príncipe de gran renombre. Anton se siente eufórico por el honor de ser abrazado por el príncipe y le ofrece su cuerpo. Sin embargo, el príncipe le susurra su amor, pero no quiere abrazar a Anton fácilmente porque piensa en el cuerpo de Anton. Impaciente, Anton se sienta a horcajadas sobre el príncipe y se frota sobre él lascivamente... ','["Romance","Adulto","Maduro","Fantasía","Drama","Realeza"]','manga','completado','scancrimson.com/covers/7ac14f57-95da-49b8-a274-9882743f140d.webp','33715907-b8ae-4d68-85c7-3534a8511c2c',2,'2026-06-24 16:24:42','2026-06-26 04:51:55','scan-7d5cc0bc',1,0,'amaregulus-el-general-de-compania',NULL,'aprobado',0);
