INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('0db49fa4-88e0-4f26-a942-bd99873e90c8','Fui Poseído en un Área Extremadamente Privada ',NULL,replace('El reportero de espectáculos Lee Joowon muere en un accidente automovilístico. Cuando abre los ojos, se encuentra en la bañera de una habitación de hotel, poseyendo el cuerpo de Jung Yeonwoo, un chaebol de segunda generación y ejecutivo de una empresa de entretenimiento.\n\nAntes de que siquiera pueda comprender la situación, suena el timbre de la puerta…\nLa abre y se encuentra frente a frente con el actor nacional Seo Heejae.\n\n—¿Será posible… que yo sea la pareja sexual de Seo Heejae?','\n',char(10)),'["Romance","Yaoi","BL (Boys Love)","Fantasía","Drama","Reencarnación","Josei"]','manhwa','en_curso','scancrimson.com/covers/0db49fa4-88e0-4f26-a942-bd99873e90c8.webp','b834ee67-f2aa-4f7d-bcd4-76e8404e02c4',1,'2026-06-27 19:25:04','2026-06-27 19:25:04','scan-4b2f06f1',1,0,'fui-poseido-en-un-area-extremadamente-privada',NULL,'aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('f0652cf7-b4c9-46bd-923d-bffe21166b10','Amor Encubierto - SIN CENSURA',NULL,replace('La tranquila vida de Lee Jae, un apasionado policía de un pequeño pueblo rural, se desmorona cuando se reencuentra con su primer amor.\n¿Quién hubiera imaginado que aquel primer amor que desapareció sin decir una sola palabra regresaría convertido en un gánster, justo frente a sus ojos?\n—Ten un poco más de paciencia. Todo lo que quedó pendiente… hoy lo voy a compensar.\nAnte ese rostro condenadamente atractivo que juró no volver a ver jamás…\n¿Podrá mantenerse firme sin dejarse sacudir por sus sentimientos?','\n',char(10)),'["Romance","Mafia","Yaoi","BL (Boys Love)","Josei","Adulto","Drama"]','manhwa','en_curso','scancrimson.com/covers/f0652cf7-b4c9-46bd-923d-bffe21166b10.webp','b834ee67-f2aa-4f7d-bcd4-76e8404e02c4',1,'2026-06-27 19:28:23','2026-06-27 19:28:23','scan-4b2f06f1',1,1,'amor-encubierto-sin-censura',NULL,'aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('af49e902-e4e6-4c3e-9a42-b86a3852f257','Clínica de urología frente al Departamento de Obstetricia y Ginecología',NULL,'“¿Debería parar? Ya es una inundación dentro de ti.” Wonyoung, sospechando que tenía frigidez, busca atención médica de su amiga Yeonwoo. “¡No! No es eso. Me duele. Me duele mucho.” “Sí.” “No te retires. Sigue.” La emocionante sensación que siente cada vez que el guante de nitrilo negro entra y sale entre sus piernas. Wonyoung no puede contener sus gemidos ante el líquido que se escapa. “Creo que estoy a punto de correrme ahora mismo. Así que, por favor, haz algo.” ','["Sadomasoquismo","Recuentos de la Vida (Slice of Life)","Maduro","Adulto","Josei"]','manhwa','completado','scancrimson.com/covers/af49e902-e4e6-4c3e-9a42-b86a3852f257.webp','686aeaa4-0719-4f9d-aae7-a145ae087c74',7,'2026-06-27 22:44:20','2026-06-28 00:44:26','scan-025989b6',1,3,'clinica-de-urologia-frente-al-departamento-de-obstetricia-y-ginecologia',NULL,'aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('e14977b9-d17f-4c4b-98c1-358a46a1bdff','Cuando el amor termina, tú también lo haces.',NULL,'Una chica que puede ver fantasmas. Ante ella aparece un fantasma llamado Baek Jeok, que ha seguido el hilo de una conexión pasada para llegar hasta ella. Él habla de amor, pero su mirada está fija en alguien totalmente distinto. Ella se convierte en una presa por el bien de su amor y, poco a poco, se pierde a sí misma. Un thriller romántico donde el límite del yo se retuerce y se deforma entre el afecto y la obsesión.','["Drama","Romance","Horror","Misterio","Sobrenatural","Shoujo"]','manhwa','en_curso','scancrimson.com/covers/e14977b9-d17f-4c4b-98c1-358a46a1bdff.webp','6b1571c9-1348-41d4-9cab-59483f9d1306',2,'2026-06-27 23:21:08','2026-06-27 23:21:08','scan-001',0,0,'cuando-el-amor-termina-tu-tambien-lo-haces',NULL,'aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('105f1a7d-8ebe-4ef2-b4e3-57cfde190c39','Extracción de amor ',NULL,'Chanhee es una gánster temible que, tras derrotar a una banda rival, sufre un repentino dolor de muelas del juicio. Al ir a una clínica dental para que se la extraigan, se enamora perdidamente de Hajin, la hermosa dentista que trabaja en el turno de noche. Aunque Hajin la rechaza cuando Chanhee la invita a salir, eso no impide que Chanhee le lleve almuerzos elegantes y regalos para conquistarla. Una cosa lleva a la otra y terminan teniendo un encuentro íntimo en la clínica, pero ¿podrá su nueva relación perdurar cuando provienen de mundos completamente diferentes?','["Maduro","Adulto","GL (Girls Love)","Médico","Mafia","Yuri"]','manhwa','completado','scancrimson.com/covers/105f1a7d-8ebe-4ef2-b4e3-57cfde190c39.webp','686aeaa4-0719-4f9d-aae7-a145ae087c74',4,'2026-07-04 16:39:06','2026-07-04 16:39:31','scan-025989b6',1,4,'extraccion-de-amor',NULL,'aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('a43ea580-321c-4bdc-85f1-f04ab67076d9','El caballero ya no sigue el dinero ciegamente',NULL,'El Caballero Imperial, Judith, fue una vez un pedazo de basura que hacía cualquier cosa si le daba dinero, quiero decir, así era en el pasado. “El señor era un caballo de ajedrez útil. Era caro" Vivió como un perro de la familia imperial, una herramienta para el gerente general y un esclavo del dinero, usó la pobreza como excusa para dejar de lado la culpa, pero lo que quedó al final fue una traición, muerte y regresó hace 6 años. Lamentablemente, anhela una nueva vida. ''Ya no voy a ser un cuchillo en movimiento por dinero''. Decidí tomar decisiones diferentes a las de mi vida anterior y deshacerme de las cosas malas una por una ... ... . "¡Sería genial si todos los caballeros del Imperio fueran tan honestos y ejemplares como el Señor!" "Cuando te unas a mis SS, te enviaré seis cofres de lingotes de oro". “¿Te moverás por mí? Pagaré el precio ". ... ... ¿Trabajaste demasiado? Incluso el comandante de los Caballeros Rojos, que nunca se había enredado en su vida, intenta explorarla ... "Prometo tratarla como es debido. ¿No te unirás a los Caballeros Rojos? " Judith está decidida a no perseguir dinero a ciegas. ¿Puede vivir una vida sin remordimientos en esta nueva vida?','["Acción","Aventura","Drama","Fantasía","Magia","Reencarnación","Romance"]','manhwa','completado','scancrimson.com/covers/a43ea580-321c-4bdc-85f1-f04ab67076d9.webp','admin-001',0,'2026-07-06 22:55:03','2026-07-06 22:55:03','scan-001',0,0,'el-caballero-ya-no-sigue-el-dinero-ciegamente',NULL,'aprobado',0);
INSERT INTO "mangas" ("id","titulo","titulo_alt","descripcion","generos","tipo","estado","cover_r2_key","uploader_id","views_total","fecha_creacion","fecha_actualizacion","scan_id","es_adulto","views_mes","slug","joint_scan_id","joint_status","es_novela") VALUES('5babecd6-7955-4386-b51b-f9956413db56','Mary y Alex ',NULL,'«La culpa del amo reside en la negligencia de la sirvienta». Marie termina recibiendo el castigo corporal en lugar de Alex, ¡una jovencita que no tiene ni pizca de inteligencia para estudiar! Al levantar su larga falda, sus hermosas piernas blancas quedan al descubierto, y un látigo afilado que corta el aire deja heridas rojas en las esbeltas piernas de Marie. Debería decirles que no golpeen a la pobre Marie, que paren, pero ¿eh? Un momento. Algo se siente raro. ¿Por qué me late el corazón tan fuerte?','["Maduro","Adulto","Sadomasoquismo","Yuri","GL (Girls Love)","Nobleza"]','manhwa','completado','scancrimson.com/covers/5babecd6-7955-4386-b51b-f9956413db56.webp','686aeaa4-0719-4f9d-aae7-a145ae087c74',3,'2026-07-07 02:43:26','2026-07-07 02:43:26','scan-025989b6',1,3,'mary-y-alex',NULL,'aprobado',0);
